358	func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
359		if group == nil || len(group.Slots) == 0 {
360			return nil, fmt.Errorf("review-group: no review slots")
361		}
362		var firstApprove *ReviewResult
363		var firstNonApprove *ReviewResult
364		var firstResult *ReviewResult
365		for _, slot := range group.Slots {
366			if slot.Result != nil && firstResult == nil {
367				firstResult = slot.Result
368			}
369			if slot.Error != "" && slot.Result == nil {
370				if firstResult != nil {
371					return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
372				}
373				return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
374			}
375			if slot.Result == nil {
376				if firstResult != nil {
377					return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
378				}
379				return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
380			}
381			res := slot.Result
382			switch res.Verdict {
383			case VerdictApprove:
384				if !reviewResultHasACEvidence(res) {
385					return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
386				}
387				if firstApprove == nil {
388					firstApprove = res
389				}
390			case VerdictRequestChanges, VerdictBlock:
391				if firstNonApprove == nil {
392					firstNonApprove = res
393				}
394			default:
395				if firstNonApprove == nil {
396					firstNonApprove = res
397				}
398			}
399		}
400		if firstNonApprove != nil {
401			return firstNonApprove, nil
402		}
403		return firstApprove, nil
404	}
405	
406	func reviewResultHasACEvidence(res *ReviewResult) bool {
407		if res == nil || res.Verdict != VerdictApprove {
408			return false
409		}
410		if len(res.PerAC) == 0 {
411			return false
412		}
413		for _, ac := range res.PerAC {
414			if strings.TrimSpace(ac.Evidence) == "" {
415				return false
416			}
417		}
418		return true
419	}
