113	// TestCostCapTracker_LookupCached asserts that the per-harness lookup
114	// is invoked at most once per harness — the tracker must not call
115	// Lookup on every Add (the lookup may make a network call).
116	func TestCostCapTracker_LookupCached(t *testing.T) {
117		var calls int
118		tr := NewCostCapTracker(100.0, func(string) bool {
119			calls++
120			return true
121		})
122		tr.Add("openrouter", 1.0)
123		tr.Add("openrouter", 1.0)
124		tr.Add("openrouter", 1.0)
125		if calls != 1 {
126			t.Fatalf("Lookup called %d times for one harness, want 1", calls)
127		}
128	}
