60	// RunPostMergeReview executes the post-merge review state machine for a
61	// successful bead attempt. When review is skipped (no reviewer or --no-review)
62	// the bead is closed and the function returns Approved=true. When review is
63	// active, the execute-loop asks the review coordinator to evaluate the
64	// close-eligible result before CloseWithEvidence runs; close only proceeds on
65	// unanimous evidence-backed APPROVE. REQUEST_CHANGES and BLOCK record their
66	// review events without reopening the bead.
67	//
68	// The review:skip label only skips when it carries a sibling
69	// review:skip-reason:* label; otherwise it is ignored. When review is not
70	// skipped, the review coordinator's verdict(s) or error drive the canonical
71	// event emissions (review / review-error / review-manual-required /
72	// review-malfunction), and on a non-APPROVE verdict the triage policy is
73	// still consulted without reopening the bead.
74	//
75	// Returns Approved=true on the APPROVE path and on the skip path; returns
76	// Approved=false on REQUEST_CHANGES, BLOCK, malformed APPROVE/BLOCK, or
77	// reviewer transport error. Store errors are surfaced via StoreErrOp +
78	// StoreErr so callers can keep the existing handleOutcomeStoreError pattern
79	// unchanged.
80	//
81	// This is the C3 (ddx-a921ff01) extraction of the 180-line review block
82	// previously inline in execute_bead_loop.go; the loop now sees a structured
83	// outcome and conflict-recovery / decomposition / no_changes paths remain
84	// in the loop body until subsequent C-series beads (C4, C5) move them too.
85	func RunPostMergeReview(ctx context.Context, in PostMergeReviewInput) PostMergeReviewOutput {
86		report := in.Report
87		out := PostMergeReviewOutput{Report: report, Approved: true}
88	
89		now := in.Now
90		if now == nil {
91			now = time.Now
92		}
93	
94		reviewSkipped := in.Reviewer == nil || in.NoReview
95		if !reviewSkipped && HasBeadLabel(in.Bead.Labels, "review:skip") {
96			reviewSkipped = HasBeadLabelPrefix(in.Bead.Labels, "review:skip-reason:")
97		}
98	
99		if reviewSkipped {
100			if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
101				out.StoreErrOp = "CloseWithEvidence"
102				out.StoreErr = err
103				return out
104			}
105			out.Report = report
106			return out
107		}
108	
109		implRouting := ImplementerRouting{
110			Harness:     report.Harness,
111			Provider:    report.Provider,
112			Model:       report.Model,
113			ActualPower: report.ActualPower,
114			Correlation: map[string]string{
115				"bead_id":    in.Bead.ID,
116				"attempt_id": report.AttemptID,
117				"session_id": report.SessionID,
118				"result_rev": report.ResultRev,
119			},
120		}
121		reviewGroup, reviewErr := runPreCloseReviewGroup(ctx, in.Reviewer, in.Bead.ID, report.ResultRev, implRouting)
122		reviewRes, reviewGroupErr := reducePreCloseReviewGroup(reviewGroup)
123		chargeReviewCost := func() bool {
124			budgetExceeded := false
125			if capTracker := in.ReviewCostCap; capTracker != nil && reviewGroup != nil {
126				deferred := false
127				for _, slot := range reviewGroup.Slots {
128					if slot.Result == nil {
129						continue
130					}
131					capTracker.Add(slot.Result.ReviewerHarness, slot.Result.CostUSD)
132					if detail, capped := capTracker.Tripped(); capped && !deferred {
133						_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
134							Kind:      "review-cost-deferred",
135							Summary:   "review-cost-deferred",
136							Body:      ReviewCostDeferredEventBody(report.ResultRev, slot.Result.CostUSD, capTracker.Spent(), capTracker.MaxUSD),
137							Actor:     in.Assignee,
138							Source:    "ddx agent execute-loop",
139							CreatedAt: now().UTC(),
140						})
141						if in.Log != nil {
142							_, _ = fmt.Fprintf(in.Log, "review cost cap deferred (%s %s): %s\n", in.Bead.ID, report.ResultRev, detail)
143						}
144						deferred = true
145						budgetExceeded = true
146					}
147				}
148			}
149			return budgetExceeded
150		}
151		if reviewGroupErr != nil {
152			reviewErr = reviewGroupErr
153		}
154		if reviewErr != nil {
155			class := ClassifyReviewError(reviewErr, reviewRes)
156			prior := CountPriorReviewErrors(in.Store, in.Bead.ID, report.ResultRev)
157			attemptCount := prior + 1
158			maxRetries := in.Rcfg.ReviewMaxRetries()
159			if maxRetries <= 0 {
160				maxRetries = DefaultReviewMaxRetries
161			}
162			errSummary := EventBodySummary{
163				InputBytes:  0,
164				OutputBytes: 0,
165			}
166			if reviewRes != nil {
167				errSummary = EventBodySummary{
168					Harness:     reviewRes.ReviewerHarness,
169					Model:       reviewRes.ReviewerModel,
170					InputBytes:  reviewRes.InputBytes,
171					OutputBytes: reviewRes.OutputBytes,
172					ElapsedMS:   reviewRes.DurationMS,
173				}
174			}
175			if attemptCount >= maxRetries {
176				body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
177				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
178					Kind:      "review-manual-required",
179					Summary:   class,
180					Body:      body,
181					Actor:     in.Assignee,
182					Source:    "ddx agent execute-loop",
183					CreatedAt: now().UTC(),
184				})
185				_ = in.Store.Update(in.Bead.ID, func(b *bead.Bead) {
186					if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
187						b.Labels = append(b.Labels, TriageNeedsHumanLabel)
188					}
189				})
190				parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
191				_ = in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, "review-manual-required", class)
192			} else {
193				body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
194				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
195					Kind:      "review-error",
196					Summary:   class,
197					Body:      body,
198					Actor:     in.Assignee,
199					Source:    "ddx agent execute-loop",
200					CreatedAt: now().UTC(),
201				})
202			}
203			if reviewRes != nil {
204				report.ReviewVerdict = string(reviewRes.Verdict)
205				report.ReviewRationale = reviewRes.Rationale
206			}
207			report.Status = ExecuteBeadStatusReviewMalfunction
208			report.Detail = "pre-close review: " + class
209			out.Report = report
210			out.Approved = false
211			chargeReviewCost()
212			return out
213		}
214	
215		report.ReviewVerdict = string(reviewRes.Verdict)
216		report.ReviewRationale = reviewRes.Rationale
217		artifactPath, artifactErr := PersistReviewerStream(in.ProjectRoot, in.Bead.ID, report.AttemptID, reviewRes.RawOutput)
218		if artifactErr != nil && in.Log != nil {
219			_, _ = fmt.Fprintf(in.Log, "reviewer stream artifact: %v\n", artifactErr)
220		}
221	
222		reviewSummary := EventBodySummary{
223			Harness:     reviewRes.ReviewerHarness,
224			Model:       reviewRes.ReviewerModel,
225			InputBytes:  reviewRes.InputBytes,
226			OutputBytes: reviewRes.OutputBytes,
227			ElapsedMS:   reviewRes.DurationMS,
228		}
229		reviewBudgetExceeded := chargeReviewCost()
230		switch reviewRes.Verdict {
231		case VerdictApprove:
232			// Approved: record the verdict event and then close. The close must
233			// land AFTER the review event so the gate sees the terminal verdict.
234			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
235				Kind:      "review",
236				Summary:   "APPROVE",
237				Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
238				Actor:     in.Assignee,
239				Source:    "ddx agent execute-loop",
240				CreatedAt: now().UTC(),
241			})
242			if reviewBudgetExceeded {
243				// Reviewer cost tripped the budget cap; leave bead open so the
244				// loop's BudgetStop can stop the drain before the next claim.
245				out.Report = report
246				out.Approved = false
247				return out
248			}
249			if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
250				out.Report = report
251				out.StoreErrOp = "CloseWithEvidence"
252				out.StoreErr = cerr
253				return out
254			}
255		case VerdictRequestChanges:
256			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
257				Kind:      "review",
258				Summary:   "REQUEST_CHANGES",
259				Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
260				Actor:     in.Assignee,
261				Source:    "ddx agent execute-loop",
262				CreatedAt: now().UTC(),
263			})
264			report.Status = ExecuteBeadStatusReviewRequestChanges
265			report.Detail = "pre-close review: REQUEST_CHANGES"
266			out.Approved = false
267		case VerdictBlock:
268			rationale := strings.TrimSpace(reviewRes.Rationale)
269			if rationale == "" {
270				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
271					Kind:      "review-malfunction",
272					Summary:   "BLOCK without rationale",
273					Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
274					Actor:     in.Assignee,
275					Source:    "ddx agent execute-loop",
276					CreatedAt: now().UTC(),
277				})
278				report.Status = ExecuteBeadStatusReviewMalfunction
279				report.Detail = "pre-close review: malformed BLOCK verdict (missing rationale)"
280				report.ReviewRationale = ""
281				out.Report = report
282				out.Approved = false
283				return out
284			}
285			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
286				Kind:      "review",
287				Summary:   "BLOCK",
288				Body:      AppendEventSummary(rationale, reviewSummary),
289				Actor:     in.Assignee,
290				Source:    "ddx agent execute-loop",
291				CreatedAt: now().UTC(),
292			})
293			if terminalClass := classifyTerminalReviewBlock(reviewRes); terminalClass != "" {
294				applyTerminalReviewBlock(in.Store, in.Bead.ID, in.Assignee, now().UTC(), terminalClass, report.ResultRev)
295				report.Status = ExecuteBeadStatusReviewTerminalBlock
296				report.Detail = "pre-close review: terminal " + terminalClass
297				out.Report = report
298				out.Approved = false
299				return out
300			}
301			// Non-terminal BLOCK: schedule one bounded repair cycle (review_fixable_gap).
302			// If a repair cycle has already been scheduled for this result_rev, fall
303			// through to the regular BLOCK triage path so the policy cannot loop.
304			if !hasReviewFixableGapRepairScheduled(in.Store, in.Bead.ID, report.ResultRev) {
305				groupID := ""
306				if reviewGroup != nil {
307					groupID = reviewGroup.Bundle.GroupID
308				}
309				repairCtx := scheduleReviewFixableGapRepair(
310					in.Store, in.Bead.ID, in.Assignee, now().UTC(),
311					groupID, report.ResultRev,
312					strings.TrimSpace(reviewRes.Rationale),
313					report.ActualPower,
314				)
315				report.Status = ExecuteBeadStatusReviewFixableGap
316				report.Detail = "pre-close review: review_fixable_gap"
317				out.Report = report
318				out.Approved = false
319				out.RepairContext = repairCtx
320				return out
321			}
322			report.Status = ExecuteBeadStatusReviewBlock
323			report.Detail = "pre-close review: BLOCK (flagged for human)"
324			out.Approved = false
325		}
326		if reviewRes.Verdict == VerdictBlock || reviewRes.Verdict == VerdictRequestChanges {
327			_ = applyReviewTriageDecision(in.Store, in.Bead.ID, in.Assignee, now().UTC(), report.Tier)
328		}
329	
330		out.Report = report
331		return out
332	}
