334	func runPreCloseReviewGroup(ctx context.Context, reviewer BeadReviewer, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error) {
335		if reviewer == nil {
336			return nil, fmt.Errorf("review-group: reviewer required")
337		}
338		if groupReviewer, ok := reviewer.(reviewGroupReviewer); ok {
339			return groupReviewer.ReviewGroup(ctx, beadID, resultRev, impl)
340		}
341		result, err := reviewer.ReviewBead(ctx, beadID, resultRev, impl)
342		group := &ReviewGroupResult{
343			BeadID:    beadID,
344			ResultRev: resultRev,
345			Slots: []ReviewGroupSlotResult{
346				{
347					ReviewerIndex: 0,
348					Result:        result,
349				},
350			},
351		}
352		if err != nil {
353			group.Slots[0].Error = err.Error()
354		}
355		return group, err
356	}
357	
358	func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
359		if group == nil || len(group.Slots) == 0 {
360			return nil, fmt.Errorf("review-group: no review slots")
361		}
362		var firstApprove *ReviewResult
363		var firstNonApprove *ReviewResult
364		var firstResult *ReviewResult
365		for _, slot := range group.Slots {
366			if slot.Result != nil && firstResult == nil {
367				firstResult = slot.Result
368			}
369			if slot.Error != "" && slot.Result == nil {
370				if firstResult != nil {
371					return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
372				}
373				return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
374			}
375			if slot.Result == nil {
376				if firstResult != nil {
377					return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
378				}
379				return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
380			}
381			res := slot.Result
382			switch res.Verdict {
383			case VerdictApprove:
384				if !reviewResultHasACEvidence(res) {
385					return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
386				}
387				if firstApprove == nil {
388					firstApprove = res
389				}
390			case VerdictRequestChanges, VerdictBlock:
391				if firstNonApprove == nil {
392					firstNonApprove = res
393				}
394			default:
395				if firstNonApprove == nil {
396					firstNonApprove = res
397				}
398			}
399		}
400		if firstNonApprove != nil {
401			return firstNonApprove, nil
402		}
403		return firstApprove, nil
404	}
405	
406	func reviewResultHasACEvidence(res *ReviewResult) bool {
407		if res == nil || res.Verdict != VerdictApprove {
408			return false
409		}
410		if len(res.PerAC) == 0 {
411			return false
412		}
413		for _, ac := range res.PerAC {
414			if strings.TrimSpace(ac.Evidence) == "" {
415				return false
416			}
417		}
418		return true
419	}
420	
421	// applyReviewTriageDecision runs the triage policy after a BLOCK or
422	// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
423	// prior review events to compute the BLOCK count, biases the result toward
424	// re-attempt when the latest BLOCK was paired with a degraded reviewer
425	// (kind:review-pairing-degraded), then applies the chosen action by writing
426	// metadata, labels, and a kind:triage-decision event.
427	//
428	// Errors from the underlying store are best-effort: callers continue
429	// regardless so a triage-side failure cannot strand a bead in an
430	// inconsistent review state. This callout previously lived as a method on
431	// ExecuteBeadWorker; the C3
432	// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
433	// driven by RunPostMergeReview / try.Attempt.
434	func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
435		events, err := store.Events(beadID)
436		if err != nil {
437			return err
438		}
439	
440		var blockTimestamps []time.Time
441		var pairingDegraded []time.Time
442		for _, ev := range events {
443			switch {
444			case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
445				blockTimestamps = append(blockTimestamps, ev.CreatedAt)
446			case ev.Kind == ReviewPairingDegradedEventKind:
447				pairingDegraded = append(pairingDegraded, ev.CreatedAt)
448			}
449		}
450	
451		// History excludes the current attempt. The just-appended BLOCK (if any)
452		// is the last entry in blockTimestamps and must not be counted as prior
453		// history per triage.Decide()'s contract.
454		historyCount := len(blockTimestamps)
455		if historyCount > 0 {
456			historyCount--
457		}
458		history := make([]triage.FailureMode, 0, historyCount)
459		for i := 0; i < historyCount; i++ {
460			history = append(history, triage.FailureModeReviewBlock)
461		}
462	
463		policy := triage.DefaultPolicy()
464		action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)
465	
466		pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
467		if pairedDegraded && action == triage.ActionEscalateTier {
468			action = triage.ActionReAttemptWithContext
469		}
470	
471		return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
472	}
473	
474	// latestBlockPairedDegraded reports whether the most recent BLOCK event was
475	// paired with a review-pairing-degraded event from the same attempt window
476	// (between the previous BLOCK and this one).
477	func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
478		if len(blocks) == 0 || len(pairing) == 0 {
479			return false
480		}
481		latest := blocks[len(blocks)-1]
482		var prev time.Time
483		if len(blocks) >= 2 {
484			prev = blocks[len(blocks)-2]
485		}
486		for _, t := range pairing {
487			if t.After(prev) && !t.After(latest) {
488				return true
489			}
490		}
491		return false
492	}
493	
494	// applyTriageAction performs the side effects for a chosen Action: writes a
495	// tier-pin hint into bead.Extra (escalate_tier), appends a needs_human label
496	// (needs_human), and always records a kind:triage-decision event.
497	func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
498		body := map[string]any{
499			"action": string(action),
500			"mode":   string(triage.FailureModeReviewBlock),
501		}
502		if pairedDegraded {
503			body["pairing_degraded"] = true
504		}
505	
506		switch action {
507		case triage.ActionEscalateTier:
508			nextTier := nextEscalatedTier(currentTier)
509			body["tier_hint"] = string(nextTier)
510			_ = store.Update(beadID, func(b *bead.Bead) {
511				if b.Extra == nil {
512					b.Extra = make(map[string]any)
513				}
514				b.Extra[TriageTierHintKey] = string(nextTier)
515			})
516		case triage.ActionNeedsHuman:
517			_ = store.Update(beadID, func(b *bead.Bead) {
518				if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
519					b.Labels = append(b.Labels, TriageNeedsHumanLabel)
520				}
521			})
522		}
523	
524		bodyJSON, _ := json.Marshal(body)
525		return store.AppendEvent(beadID, bead.BeadEvent{
526			Kind:      triageDecisionEventKind,
527			Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
528			Body:      string(bodyJSON),
529			Actor:     actor,
530			Source:    "ddx agent execute-loop",
531			CreatedAt: now,
532		})
533	}
534	
535	// nextEscalatedTier returns the next tier above `current`. An unrecognised or
536	// empty current tier defaults to standard; smart is its own ceiling.
537	func nextEscalatedTier(current string) escalation.ModelTier {
538		switch escalation.ModelTier(current) {
539		case escalation.TierCheap:
540			return escalation.TierStandard
541		case escalation.TierStandard:
542			return escalation.TierSmart
543		case escalation.TierSmart:
544			return escalation.TierSmart
545		default:
546			return escalation.TierStandard
547		}
548	}
